import React, { Component } from 'react'
import { TabBar } from 'antd-mobile'
// 导入路由
import { Route } from 'react-router-dom'
// 导入样式
import './index.css'
// 导入子组件
import Index from '../Index'
import News from '../News'

export default class Home extends Component {
  state = {
    selectedTab: 'redTab',
  }

  render() {
    return (
      <div>
        {/* 渲染子路由 */}
        <Route path='/home/news' component={News}></Route>
        <Route path='/home/index' component={Index}></Route>
        {/* tabbar */}

        <div style={{ position: 'fixed', width: '100%', bottom: 0 }}>
          <TabBar
            unselectedTintColor="#949494"
            tintColor="#33A3F4"
            barTintColor="white"
            noRenderContent="true"
          >
            <TabBar.Item
              title="首页"
              key="Home"
              icon={ <span className='iconfont icon-home_light'></span> }
              selectedIcon={ <span className='iconfont icon-home_light'></span> }
              selected={this.state.selectedTab === '/home/index'}
              onPress={() => {
                this.setState({
                  selectedTab: '/home/index',
                });
                this.props.history.push('/home/index')
              }}
              data-seed="logId"
            >
            </TabBar.Item>
            <TabBar.Item
              icon={ <span className='iconfont icon-search'></span> }
              selectedIcon={ <span className='iconfont icon-search'></span> }
              title="找房"
              key="Search"
              selected={this.state.selectedTab === 'redTab'}
              onPress={() => {
                this.setState({
                  selectedTab: 'redTab',
                });
              }}
              data-seed="logId1"
            >
            </TabBar.Item>
            <TabBar.Item
              icon={ <span className='iconfont icon-Message'></span> }
              selectedIcon={ <span className='iconfont icon-Message'></span> }
              title="资讯"
              key="Message"
              selected={this.state.selectedTab === '/home/news'}
              onPress={() => {
                this.setState({
                  selectedTab: '/home/news',
                });
                this.props.history.push('/home/news')
              }}
            >
            </TabBar.Item>
            <TabBar.Item
              icon={ <span className='iconfont icon-mine'></span> }
              selectedIcon={ <span className='iconfont icon-mine'></span> }
              title="我的"
              key="Mine"
              selected={this.state.selectedTab === 'yellowTab'}
              onPress={() => {
                this.setState({
                  selectedTab: 'yellowTab',
                });
              }}
            >
            </TabBar.Item>
          </TabBar>
        </div>

      </div>
    )
  }
}
